// Clean transcript
let transcript = ($json.data || "")
  .replace(/Speaker\s*\d+:\s*\d{2}:\d{2}/g, "")
  .replace(/Speaker\s*\d+:/g, "")
  .toLowerCase();

// Get file name
const fileName = $binary?.data?.fileName || "unknown_account.txt";
const accountIdFromFile = fileName.replace(".txt", "").toLowerCase();


// -----------------------------
// Extract Company Name
// -----------------------------
function extractCompanyName(text) {

  if (/ben.?s electric/i.test(text)) {
    return "Ben's Electric Solutions";
  }

  const patterns = [
    /company name is ([^.]+)/i,
    /our company is ([^.]+)/i,
    /this is ([^.]+) from/i
  ];

  for (const p of patterns) {
    const match = text.match(p);
    if (match) return match[1].trim();
  }

  return "";
}


// -----------------------------
// Extract Business Hours
// -----------------------------
function extractBusinessHours(text) {

  const match = text.match(/open (.+?) from (.+?) to (.+?)\./i);

  if (!match) return {};

  return {
    days: match[1].trim(),
    start: match[2].trim(),
    end: match[3].trim(),
    timezone: ""
  };
}


// -----------------------------
// Extract Services
// -----------------------------
function extractServices(text) {

  const services = [];

  if (/ev charger/i.test(text)) {
    services.push("EV charger installation");
  }

  if (/hot tub/i.test(text)) {
    services.push("hot tub electrical hookup");
  }

  if (/panel/i.test(text)) {
    services.push("panel upgrades");
  }

  if (/renovation/i.test(text)) {
    services.push("electrical renovations");
  }

  if (/troubleshoot/i.test(text)) {
    services.push("electrical troubleshooting");
  }

  if (/service call/i.test(text)) {
    services.push("electrical service calls");
  }

  if (/commercial/i.test(text)) {
    services.push("commercial electrical work");
  }

  if (/residential/i.test(text)) {
    services.push("residential electrical work");
  }

  return services;
}


// -----------------------------
// Extract Integrations
// -----------------------------
function extractIntegrations(text) {

  const integrations = [];

  if (/jobber/i.test(text)) {
    integrations.push("Uses Jobber CRM");
  }

  if (/servicetitan/i.test(text)) {
    integrations.push("ServiceTitan integration");
  }

  if (/housecall/i.test(text)) {
    integrations.push("Housecall Pro integration");
  }

  if (/quickbooks/i.test(text)) {
    integrations.push("QuickBooks accounting integration");
  }

  return integrations;
}


// -----------------------------
// Extract Emergency Definitions
// -----------------------------
function extractEmergencyDefinition(text) {

  const emergencies = [];

  if (/emergency/i.test(text)) {
    emergencies.push("electrical emergencies");
  }

  if (/gas station pump/i.test(text)) {
    emergencies.push("gas station pump failures");
  }

  return emergencies;
}


// -----------------------------
// Extract After Hours Rules
// -----------------------------
function extractAfterHours(text) {

  if (/after hours/i.test(text) || /weekend/i.test(text)) {
    return "Owner handles emergency calls after hours.";
  }

  return "";
}


// -----------------------------
// Run Extraction
// -----------------------------
const companyName = extractCompanyName(transcript);
const businessHours = extractBusinessHours(transcript);
const services = extractServices(transcript);
const integrations = extractIntegrations(transcript);
const emergencies = extractEmergencyDefinition(transcript);
const afterHours = extractAfterHours(transcript);


// -----------------------------
// Generate Account ID
// -----------------------------
let accountId = accountIdFromFile;

if (!accountId || accountId === "unknown_account") {

  accountId = companyName
    ? companyName.toLowerCase().replace(/[^a-z0-9]/g, "_")
    : "unknown_account";
}


// -----------------------------
// Detect Missing Information
// -----------------------------
const questions = [];

if (!companyName) {
  questions.push("Company name not clearly stated in demo call.");
}

if (!businessHours.days || !businessHours.start || !businessHours.end) {
  questions.push("Business hours not fully specified.");
}

if (!businessHours.timezone) {
  questions.push("Timezone not specified.");
}

if (!emergencies.length) {
  questions.push("Emergency definition not clearly provided.");
}

if (!afterHours) {
  questions.push("After-hours routing rules not specified.");
}

questions.push("Primary emergency contact not defined.");
questions.push("Transfer retry policy not specified.");

if (!integrations.length) {
  questions.push("Integration constraints not specified.");
}


// -----------------------------
// Build Memo
// -----------------------------
const accountMemo = {

  account_id: accountId,

  company_name: companyName,

  business_hours: businessHours,

  office_address: "",

  services_supported: services,

  emergency_definition: emergencies,

  emergency_routing_rules: {
    primary_contact: "",
    secondary_contact: "",
    transfer_timeout_seconds: null,
    fallback_action: afterHours
  },

  non_emergency_routing_rules: {
    during_hours: "",
    after_hours: ""
  },

  call_transfer_rules: {
    max_retries: null,
    retry_delay_seconds: null,
    failure_message: ""
  },

  integration_constraints: integrations,

  after_hours_flow_summary: afterHours,

  office_hours_flow_summary: "",

  questions_or_unknowns: questions,

  notes: "Generated from demo call transcript (v1)"
};


// Return result
return [{
  json: accountMemo
}];
